Question 1: How many graduate students were enrolled at Baruch in 2024?
There were 11243 distinct institutions in the dataset.

# How many graduate students were enrolled at Baruch in 2024?

IPEDS |&gt;
  filter(
    str_detect(institution_name, "Baruch"),
    year == 2024,
    level == "all graduate"
  ) |&gt;
  summarise(baruch_graduate_students = sum(across(starts_with("enrollment_")))) # There are 3,585

# A tibble: 1 × 1
  baruch_graduate_students
                     &lt;dbl&gt;
1                     3585



# How many total students were enrolled at Baruch in 2024?

IPEDS |&gt;
  filter(
    str_detect(institution_name, "Baruch"),
    year == 2024,
    level != "first year undergrad" # This avoids the double count for all undergrad and first year undergrad
  ) |&gt;
  summarise(baruch_total_students = sum(across(starts_with("enrollment_")))) # There are 20,081

# A tibble: 1 × 1
  baruch_total_students
                  &lt;dbl&gt;
1                 20081

Question 2: How many total students were enrolled at Baruch in 2024?
In 2024, Baruch enrolled 2.0081^{4} total students.

# Which institution had the highest number of enrolled female students in 2019?

IPEDS |&gt;
  filter(
    year == 2019,
    level %in% c("all undergrad", "all graduate") # Avoids double counting first year students
  ) |&gt;
  mutate(total_female = enrollment_f_aian + enrollment_f_asia + enrollment_f_bkaa +
                        enrollment_f_hisp + enrollment_f_nhpi + enrollment_f_whit +
                        enrollment_f_2mor + enrollment_f_unkn + enrollment_f_nral) |&gt;
  group_by(institution_name) |&gt;
  summarise(total_female_students = sum(total_female), .groups = "drop") |&gt;
  arrange(desc(total_female_students)) |&gt; # Orders from highest to lowest
  slice(1) # Pulls the first row (which is the institution with the most female students)

# A tibble: 1 × 2
  institution_name             total_female_students
  &lt;chr&gt;                                        &lt;dbl&gt;
1 Western Governors University                 88877



# Which institution with over 1000 total students admitted the highest proportion of Native Hawaiian or Pacific Islander (nhpi) first-year undergraduates in 2024?

IPEDS |&gt;
  filter(year == 2024) |&gt;
  mutate( # Creates a new column that has the total amount of students
    total_enrollment =
      enrollment_m_aian + enrollment_f_aian +
      enrollment_m_asia + enrollment_f_asia +
      enrollment_m_bkaa + enrollment_f_bkaa +
      enrollment_m_hisp + enrollment_f_hisp +
      enrollment_m_nhpi + enrollment_f_nhpi +
      enrollment_m_whit + enrollment_f_whit +
      enrollment_m_2mor + enrollment_f_2mor +
      enrollment_m_unkn + enrollment_f_unkn +
      enrollment_m_nral + enrollment_f_nral,
    nhpi_enrollment = enrollment_m_nhpi + enrollment_f_nhpi # New column that has the total amount of nhpi students
  ) |&gt;
  group_by(institution_name) |&gt;
  summarise(
    total_students = sum(total_enrollment[level %in% c("all undergrad", "all graduate")]),
    nhpi_first_year = sum(nhpi_enrollment[level == "first year undergrad"]),
    total_first_year = sum(total_enrollment[level == "first year undergrad"]),
    .groups = "drop"
  ) |&gt;
  filter(total_students &gt; 1000, total_first_year &gt; 0) |&gt;
  mutate(nhpi_fraction = nhpi_first_year / total_first_year) |&gt;
  arrange(desc(nhpi_fraction)) |&gt; # Orders from highest fraction to lowest
  select(institution_name, nhpi_fraction) |&gt;
  slice(1) # Pulls the highest fraction

# A tibble: 1 × 2
  institution_name          nhpi_fraction
  &lt;chr&gt;                             &lt;dbl&gt;
1 College of Micronesia-FSM         0.996

